// 从Bellkeeper API响应中提取RSS源并构建URL
// 补录模式：为 RSSHub 源追加 ?limit=N 获取更多条目
let rssLimit = 0;
let isBackfill = false;
try {
  const webhookData = $('补录触发').first().json;
  const body = webhookData.body || webhookData;
  rssLimit = parseInt(body.limit) || 200;
  isBackfill = true;
} catch(e) {
  // 定时触发，不追加 limit
}

const response = $input.first().json;
const sources = response.data || response.items || response;

const results = [];
for (const source of sources) {
  let feedUrl = source.url;
  if (feedUrl.startsWith('/')) {
    feedUrl = 'http://rsshub:1200' + feedUrl;
    // 补录模式为 RSSHub 源追加 limit 参数
    if (isBackfill && rssLimit > 0) {
      feedUrl += (feedUrl.includes('?') ? '&' : '?') + 'limit=' + rssLimit;
    }
  }

  const sourceTags = (source.tags || []).map(t => typeof t === 'object' ? (t.name || '') : String(t)).filter(t => t);
  if (source.category && !sourceTags.includes(source.category)) {
    sourceTags.push(source.category);
  }

  results.push({
    json: {
      id: source.id,
      name: source.name,
      feedUrl: feedUrl,
      originalUrl: source.url,
      category: source.category || '',
      tags: sourceTags,
      isActive: source.is_active,
      _isBackfill: isBackfill,
      _rssLimit: rssLimit
    }
  });
}

return results;

// 将所有Feed响应与RSS源信息按索引配对，解析所有文章
const feeds = $input.all();
const sources = $('提取RSS源').all();

function extractTag(content, tag) {
  const cdataRegex = new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>`, 'i');
  const plainRegex = new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i');
  const hrefRegex = new RegExp(`<${tag}[^>]*href=["']([^"']+)["']`, 'i');
  let match = content.match(cdataRegex);
  if (match) return match[1].trim();
  match = content.match(plainRegex);
  if (match) return match[1].trim();
  if (tag === 'link') {
    match = content.match(hrefRegex);
    if (match) return match[1].trim();
  }
  return '';
}

const allArticles = [];

for (let i = 0; i < feeds.length; i++) {
  const feedData = feeds[i].json;
  const source = sources[i] ? sources[i].json : {};
  const xml = feedData.data || feedData.body || '';

  if (!xml || typeof xml !== 'string') continue;

  const itemRegex = /<item[^>]*>[\s\S]*?<\/item>/gi;
  const entryRegex = /<entry[^>]*>[\s\S]*?<\/entry>/gi;
  const regex = xml.includes('<entry') ? entryRegex : itemRegex;

  let matches;
  while ((matches = regex.exec(xml)) !== null) {
    const itemXml = matches[0];
    const title = extractTag(itemXml, 'title');
    const link = extractTag(itemXml, 'link');
    if (title && link) {
      allArticles.push({
        json: {
          url: link,
          title: title,
          tags: source.tags || [],
          category: source.category || '',
          sourceName: source.name || ''
        }
      });
    }
  }
}

if (allArticles.length === 0) {
  return [{ json: { _noArticles: true, _sourceCount: sources.length } }];
}

return allArticles;

// Extract document IDs from successful upload responses
const results = $input.all();
const documents = [];

for (const item of results) {
  let d = item.json;

  // Handle wrapped response (body/data field)
  if (d.body && typeof d.body === 'object') d = d.body;
  if (d.data && typeof d.data === 'object' && !d.dataset_id) d = d.data;

  // Only process successful uploads
  if (d.success === true && d.uploadResult) {
    const ragflowResp = d.uploadResult.data;
    const datasetId = d.uploadResult.dataset_id;

    if (!ragflowResp || !datasetId) continue;

    const docData = ragflowResp.data || ragflowResp;
    let docId = null;

    if (Array.isArray(docData) && docData.length > 0 && docData[0].id) {
      docId = docData[0].id;
    } else if (typeof docData === 'object' && docData.id) {
      docId = docData.id;
    }

    if (docId) {
      documents.push({
        document_id: docId,
        dataset_id: datasetId,
        title: d.title || 'Untitled',
        url: d.url || ''
      });
    }
  }
}

return [{ json: { documents, count: documents.length } }];

// Group document IDs by dataset_id, output as smart parse items array
const input = $input.first().json;
const documents = input.documents || [];

const grouped = {};
for (const doc of documents) {
  const datasetId = doc.dataset_id;
  if (!grouped[datasetId]) {
    grouped[datasetId] = {
      dataset_id: datasetId,
      document_ids: []
    };
  }
  grouped[datasetId].document_ids.push(doc.document_id);
}

const items = Object.values(grouped);
return [{ json: { items, total: documents.length } }];

const now = new Date();
const hour = now.getHours();
let period = '早间';
if (hour >= 11 && hour < 15) period = '午间';
else if (hour >= 17) period = '晚间';

// 检测补录模式
let isBackfill = false;
let rssLimit = 0;
try {
  const wh = $('补录触发').first().json;
  isBackfill = true;
  rssLimit = parseInt((wh.body || wh).limit) || 200;
} catch(e) {}

const modeLabel = isBackfill ? '手动补录' : period + 'RSS定时采集';

let sourceCount = 0;
try { sourceCount = $('提取RSS源').all().length; } catch(e) {}

// 构建原始文章标题映射 (K01响应可能丢失标题)
const origArticles = $('解析全部文章').all().filter(a => a.json.url);
const titleByUrl = {};
for (const a of origArticles) {
  titleByUrl[a.json.url] = a.json.title || '';
}

const articleResults = $('推送文章到Ingest').all();
const successList = [];
const duplicateList = [];
const failedList = [];

for (let i = 0; i < articleResults.length; i++) {
  const d = articleResults[i].json;
  // 标题: 优先用K01响应 → 回退到URL匹配 → 回退到索引匹配 → Untitled
  const origByIdx = (i < origArticles.length) ? origArticles[i].json : {};
  const title = d.title || titleByUrl[d.url] || origByIdx.title || 'Untitled';
  const url = d.url || origByIdx.url || '';
  const category = d.category || origByIdx.category || '';
  const item = { title, url, category };

  if (d.error) {
    // httpRequest 错误 (Invalid JSON, timeout 等)
    item.error = typeof d.error === 'object' ? (d.error.message || JSON.stringify(d.error)) : String(d.error);
    failedList.push(item);
  } else if (d.success === false) {
    if (d.status === 'duplicate') {
      duplicateList.push(item);
    } else {
      // scrape_failed, upload_failed 等
      item.error = d.message || d.error || d.status || 'unknown error';
      failedList.push(item);
    }
  } else {
    successList.push(item);
  }
}

const total = articleResults.length;
const success = successList.length;
const duplicate = duplicateList.length;
const failed = failedList.length;

let parseTotal = 0;
let parseTaskId = '';
try {
  const parseResult = $('智能解析文档').first().json;
  parseTotal = parseResult.total_documents || 0;
  parseTaskId = parseResult.task_id || '';
} catch(e) {}

const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const timeStr = `${String(hour).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;

const plainText = `${modeLabel}已完成\n${dateStr} ${timeStr}${isBackfill ? ' | limit=' + rssLimit : ''}\nRSS源: ${sourceCount} 个 | 文章: ${total} 篇\n入库: ${success} | 已存在: ${duplicate} | 失败: ${failed}${parseTotal > 0 ? `\n已启动智能解析 (${parseTotal} 个文档${parseTaskId ? ', task=' + parseTaskId : ''})` : ''}`;

let html = `<h4>${modeLabel}完成</h4>\n<p><i>${dateStr} ${timeStr} | ${sourceCount} 个源 | ${total} 篇文章${isBackfill ? ' | limit=' + rssLimit : ''}</i></p>\n`;

if (success > 0) {
  html += `\n<h5>成功入库 (${success} 篇)</h5>\n<ul>\n`;
  const showCount = Math.min(10, success);
  for (let i = 0; i < showCount; i++) {
    const a = successList[i];
    html += `<li>${a.category ? `<b>${a.category}</b>: ` : ''}<a href="${a.url}">${a.title}</a></li>\n`;
  }
  if (success > 10) html += `<li><i>... 还有 ${success - 10} 篇</i></li>\n`;
  html += `</ul>\n`;
}

if (duplicate > 0) {
  html += `\n<p>已存在: ${duplicate} 篇 (已跳过)</p>\n`;
}

if (failed > 0) {
  html += `\n<h5>失败 (${failed} 篇)</h5>\n<ul>\n`;
  const showFailed = Math.min(5, failed);
  for (let i = 0; i < showFailed; i++) {
    const a = failedList[i];
    html += `<li><del>${a.url || a.title}</del> - ${a.error}</li>\n`;
  }
  if (failed > 5) html += `<li><i>... 还有 ${failed - 5} 篇</i></li>\n`;
  html += `</ul>\n`;
}

if (parseTotal > 0) {
  html += `\n<p>已启动智能解析: ${parseTotal} 个文档 (后台处理中，完成后会单独通知)</p>`;
}

return [{ json: { summary: plainText, html, timestamp: now.toISOString() } }];

// 无文章时也发送通知
const now = new Date();
const hour = now.getHours();
let period = '早间';
if (hour >= 11 && hour < 15) period = '午间';
else if (hour >= 17) period = '晚间';

let isBackfill = false;
try { $('补录触发').first(); isBackfill = true; } catch(e) {}
const modeLabel = isBackfill ? '手动补录' : period + 'RSS定时采集';

let sourceCount = 0;
try { sourceCount = $('提取RSS源').all().length; } catch(e) {}

const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const timeStr = `${String(hour).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;

const summary = `${modeLabel}已完成\n${dateStr} ${timeStr}\nRSS源: ${sourceCount} 个 | 文章: 0 篇 (无新内容)`;
const html = `<h4>${modeLabel}完成</h4>\n<p><i>${dateStr} ${timeStr} | ${sourceCount} 个源 | 0 篇文章</i></p>\n<p><i>无新内容</i></p>`;

return [{ json: { summary, html, timestamp: now.toISOString() } }];
